  def fetchUrl(urlRequest: UrlRequest): Future[ProxyResponse] = {
    val method = urlRequest.method.getOrElse("GET") match {
      case "GET" => HttpMethods.GET
      case "POST" => HttpMethods.POST
      case "PUT" => HttpMethods.PUT
      case "DELETE" => HttpMethods.DELETE
      case "PATCH" => HttpMethods.PATCH
      case _ => HttpMethods.GET
    }

    val headers = urlRequest.headers.getOrElse(Map.empty).map {
      case (key, value) => HttpHeader.parse(key, value) match {
        case HttpHeader.ParsingResult.Ok(header, _) => header
        case _ => throw new IllegalArgumentException(s"Invalid header: $key")
